// ============================================================
// Call Groq API with fetch() and parse the story JSON response
// ============================================================
const webhookData = $('Webhook Trigger').first().json.body;
const theme = webhookData.theme;
const project_id = webhookData.project_id;

if (!project_id || !theme) {
  throw new Error('Missing project_id or theme from webhook');
}

const GROQ_API_KEY = $vars.GROQ_API_KEY;

const groqBody = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 4096,
  temperature: 0.7,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'Tu es un auteur de livres pour enfants de 8 ans. Tu reponds UNIQUEMENT en JSON valide. Pas de texte avant ou apres le JSON. Pas de markdown.'
    },
    {
      role: 'user',
      content: 'Genere une courte histoire pour enfants sur le theme : "' + theme + '".\n\nDecoupe-la en exactement 3 scenes.\n\nReponds avec ce JSON exact :\n{\n  "story": "texte complet",\n  "moral": "la morale",\n  "scenes": [\n    {\n      "scene_number": 1,\n      "visual_description": "A colorful cartoon scene showing...",\n      "narration": "texte de narration en francais",\n      "duration_seconds": 10\n    },\n    {\n      "scene_number": 2,\n      "visual_description": "A bright animated scene where...",\n      "narration": "texte de narration en francais",\n      "duration_seconds": 10\n    },\n    {\n      "scene_number": 3,\n      "visual_description": "A cheerful cartoon finale with...",\n      "narration": "texte de narration en francais",\n      "duration_seconds": 10\n    }\n  ]\n}'
    }
  ]
};

// Call Groq via fetch - bypasses N8N HTTP Request Buffer bug
const groqRes = await fetch('https://api.groq.com/openai/v1/chat/completions', {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer ' + GROQ_API_KEY,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(groqBody)
});

if (!groqRes.ok) {
  const errText = await groqRes.text();
  throw new Error('Groq API error ' + groqRes.status + ': ' + errText.slice(0, 500));
}

const groqJson = await groqRes.json();

// Extract content from Groq response
let rawContent = '';
try {
  rawContent = groqJson.choices[0].message.content;
} catch(e) {
  throw new Error('Bad Groq response structure: ' + JSON.stringify(groqJson).slice(0, 500));
}

if (!rawContent || rawContent.trim().length === 0) {
  throw new Error('Groq returned empty content');
}

// Clean markdown fences if present
let cleaned = rawContent.trim();
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('JSON parse failed: ' + e.message + ' | Start: ' + cleaned.slice(0, 300));
}

if (!parsed.scenes || !Array.isArray(parsed.scenes) || parsed.scenes.length === 0) {
  throw new Error('No scenes in response. Keys: ' + Object.keys(parsed).join(', '));
}

const scenes = parsed.scenes.map((s, i) => ({
  scene_number: s.scene_number || (i + 1),
  visual_description: s.visual_description || 'A colorful cartoon scene for children',
  narration: s.narration || '',
  duration_seconds: s.duration_seconds || 10
}));

return [{
  json: {
    project_id,
    theme,
    story: parsed.story || '',
    moral: parsed.moral || '',
    scenes
  }
}];

// ============================================================
// Generate ElevenLabs TTS for each scene via fetch()
// ============================================================
const data = $('Call and Parse Groq').first().json;
const project_id = data.project_id;
const scenes = data.scenes;
const ELEVENLABS_KEY = $vars.ELEVENLABS_API_KEY;
const ELEVENLABS_VOICE = $vars.ELEVENLABS_VOICE_ID;
const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Notify step 3
try {
  await fetch(LARAVEL_URL + '/api/n8n/step', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-N8N-Secret': SECRET },
    body: JSON.stringify({ project_id, step: 3 })
  });
} catch(e) { /* ignore */ }

const results = [];

for (const scene of scenes) {
  let audioOk = false;
  try {
    const ttsRes = await fetch('https://api.elevenlabs.io/v1/text-to-speech/' + ELEVENLABS_VOICE, {
      method: 'POST',
      headers: {
        'xi-api-key': ELEVENLABS_KEY,
        'Content-Type': 'application/json',
        'Accept': 'audio/mpeg'
      },
      body: JSON.stringify({
        text: scene.narration,
        model_id: 'eleven_multilingual_v2',
        voice_settings: { stability: 0.7, similarity_boost: 0.8 }
      })
    });
    audioOk = ttsRes.ok;
  } catch(e) {
    audioOk = false;
  }

  results.push({
    scene_number: scene.scene_number,
    visual_description: scene.visual_description,
    narration: scene.narration,
    duration_seconds: scene.duration_seconds,
    audio_generated: audioOk
  });
}

return [{
  json: {
    project_id,
    theme: data.theme,
    story: data.story,
    moral: data.moral,
    scenes: results
  }
}];

// ============================================================
// Generate Replicate video for each scene + poll until done
// ============================================================
const data = $input.first().json;
const project_id = data.project_id;
const scenes = data.scenes;
const REPLICATE_TOKEN = $vars.REPLICATE_API_TOKEN;
const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Notify step 4
try {
  await fetch(LARAVEL_URL + '/api/n8n/step', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-N8N-Secret': SECRET },
    body: JSON.stringify({ project_id, step: 4 })
  });
} catch(e) { /* ignore */ }

const sceneResults = [];

for (const scene of scenes) {
  let videoUrl = '';
  try {
    const createRes = await fetch('https://api.replicate.com/v1/models/minimax/video-01/predictions', {
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + REPLICATE_TOKEN,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ input: { prompt: scene.visual_description } })
    });

    const createData = await createRes.json();
    const predictionId = createData.id;

    if (!predictionId) {
      throw new Error('No prediction ID: ' + JSON.stringify(createData).slice(0, 200));
    }

    let status = 'starting';
    let output = null;
    for (let attempt = 0; attempt < 20; attempt++) {
      await new Promise(resolve => setTimeout(resolve, 15000));
      const pollRes = await fetch('https://api.replicate.com/v1/predictions/' + predictionId, {
        headers: { 'Authorization': 'Bearer ' + REPLICATE_TOKEN }
      });
      const pollData = await pollRes.json();
      status = pollData.status;
      if (status === 'succeeded') { output = pollData.output; break; }
      if (status === 'failed' || status === 'canceled') {
        throw new Error('Prediction ' + status + ': ' + (pollData.error || 'unknown'));
      }
    }

    if (status === 'succeeded' && output) {
      videoUrl = Array.isArray(output) ? output[0] : String(output);
    } else if (status !== 'succeeded') {
      throw new Error('Timed out, status: ' + status);
    }
  } catch(e) {
    videoUrl = 'error: ' + e.message;
  }

  sceneResults.push({
    scene_number: scene.scene_number,
    visual_description: scene.visual_description,
    narration: scene.narration,
    duration_seconds: scene.duration_seconds,
    video_url: videoUrl
  });
}

return [{
  json: {
    project_id,
    theme: data.theme,
    story: data.story,
    moral: data.moral,
    scenes: sceneResults
  }
}];

// ============================================================
// Send final callback to Laravel with all results
// ============================================================
const data = $input.first().json;
const project_id = data.project_id;
const story = data.story || '';
const scenes = data.scenes || [];

let videoUrl = '';
for (const s of scenes) {
  if (s.video_url && !s.video_url.startsWith('error:')) {
    videoUrl = s.video_url;
    break;
  }
}

const scenesJson = scenes.map(s => ({
  scene_number: s.scene_number,
  narration: s.narration || '',
  visual_description: s.visual_description || '',
  duration_seconds: s.duration_seconds || 10
}));

const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

const callbackRes = await fetch(LARAVEL_URL + '/api/n8n/callback', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-N8N-Secret': SECRET
  },
  body: JSON.stringify({
    project_id: project_id,
    video_url: videoUrl || 'https://demo-placeholder.example.com/video.mp4',
    story_text: story,
    scenes_json: scenesJson
  })
});

const callbackBody = await callbackRes.text();

return [{
  json: {
    project_id,
    callback_status: callbackRes.status,
    callback_response: callbackBody,
    video_url: videoUrl,
    total_scenes: scenes.length
  }
}];
